Ini implementasi Observer pattern yang siap production. Saya sertakan thread-safety (`threading.Lock`) dan manajemen memori (`weakref`) untuk mencegah memory leak pada sistem jangka panjang.

```python
import weakref
import threading
from abc import ABC, abstractmethod
from typing import Any, List


class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass


class Subject:
    def __init__(self) -> None:
        self._observers: List[weakref.ref] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        with self._lock:
            # Gunakan weakref untuk mencegah circular reference memory leak
            self._observers.append(weakref.ref(observer))

    def detach(self, observer: Observer) -> None:
        with self._lock:
            self._observers = [ref for ref in self._observers if ref() is not observer]

    def notify(self) -> None:
        with self._lock:
            for observer_ref in self._observers:
                observer = observer_ref()
                if observer:
                    try:
                        observer.update(self)
                    except Exception as e:
                        # Log error tanpa menghentikan notifikasi ke observer lain
                        print(f"[CRITICAL] Observer failed: {e}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state


# Contoh Implementasi Concrete
class SecurityAlertObserver(Observer):
    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        if state.get('type') == 'security_breach':
            print(f"[ALERT] Deteksi anomali: {state.get('details')}")

class LogObserver(Observer):
    def update(self, subject: Subject) -> None:
        print(f"[LOG] System state updated: {subject.get_state()}")


# Usage
if __name__ == "__main__":
    subject = Subject()
    security_obs = SecurityAlertObserver()
    log_obs = LogObserver()

    subject.attach(security_obs)
    subject.attach(log_obs)

    # Simulasi event
    subject.set_state({'type': 'security_breach', 'details': 'SQL Injection attempt detected'})
    subject.set_state({'type': 'normal', 'details': 'Routine check'})
```

### Catatan Teknis:
1.  **Thread Safety**: Menggunakan `threading.Lock` pada metode `attach`, `detach`, dan `notify`. Wajib untuk environment multi-threaded seperti server web atau worker background.
2.  **Memory Management**: Menggunakan `weakref`. Tanpa ini, observer yang tidak lagi digunakan tidak akan di-garbage collected jika masih terdaftar di subject, menyebabkan memory leak.
3.  **Error Isolation**: `try-except` pada `notify` memastikan jika satu observer crash, observer lain tetap menerima notifikasi. Penting untuk sistem monitoring.

