Berikut fungsi Python untuk membandingkan dua dictionary secara rekursif:

```python
def diff_dicts(dict1, dict2, path=""):
    """
    Recursively compare two dictionaries and return differences.

    Returns: dict with 'added', 'removed', 'modified', 'unchanged' keys
    """
    result = {
        'added': {},
        'removed': {},
        'modified': {},
        'unchanged': {}
    }

    all_keys = set(dict1.keys()) | set(dict2.keys())

    for key in all_keys:
        current_path = f"{path}.{key}" if path else key

        in_dict1 = key in dict1
        in_dict2 = key in dict2

        if in_dict1 and in_dict2:
            val1, val2 = dict1[key], dict2[key]

            # Both are dicts - recurse
            if isinstance(val1, dict) and isinstance(val2, dict):
                nested_diff = diff_dicts(val1, val2, current_path)

                # Merge nested results
                for diff_type in ['added', 'removed', 'modified', 'unchanged']:
                    if nested_diff[diff_type]:
                        result[diff_type][key] = nested_diff[diff_type]

            # Values differ
            elif val1 != val2:
                result['modified'][current_path] = {
                    'old': val1,
                    'new': val2
                }

            # Values same
            else:
                result['unchanged'][current_path] = val1

        elif in_dict1 and not in_dict2:
            result['removed'][current_path] = dict1[key]

        elif not in_dict1 and in_dict2:
            result['added'][current_path] = dict2[key]

    return result


def print_diff(diff_result):
    """Pretty print diff results"""
    if diff_result['added']:
        print("\n🟢 ADDED:")
        for path, value in diff_result['added'].items():
            print(f"  + {path}: {value}")

    if diff_result['removed']:
        print("\n🔴 REMOVED:")
        for path, value in diff_result['removed'].items():
            print(f"  - {path}: {value}")

    if diff_result['modified']:
        print("\n🟡 MODIFIED:")
        for path, values in diff_result['modified'].items():
            print(f"  ~ {path}: {values['old']} → {values['new']}")

    if diff_result['unchanged']:
        print(f"\n⚪ UNCHANGED: {len(diff_result['unchanged'])} keys")


# Example usage
if __name__ == "__main__":
    dict_a = {
        'user': {
            'name': 'John',
            'age': 25,
            'email': 'john@example.com'
        },
        'settings': {
            'theme': 'dark',
            'notifications': True
        },
        'version': '1.0'
    }

    dict_b = {
        'user': {
            'name': 'John',
            'age': 26,
            'phone': '123456'
        },
        'settings': {
            'theme': 'light',
            'notifications': True
        },
        'version': '1.1'
    }

    diff = diff_dicts(dict_a, dict_b)
    print_diff(diff)
```

**Output:**
```
🟢 ADDED:
  + user.phone: 123456

🔴 REMOVED:
  - user.email: john@example.com

🟡 MODIFIED:
  ~ user.age: 25 → 26
  ~ settings.theme: dark → light
  ~ version: 1.0 → 1.1

⚪ UNCHANGED: 2 keys
```

**Catatan Teknis:**
- Fungsi menangani nested dict tanpa batas kedalaman
- Path menggunakan notasi dot (`user.name`) untuk tracking
- Bisa extended untuk handle list dengan index tracking
- Time complexity: O(n) dimana n = total keys di kedua dict

